def calculate_risk_score(GAP_score, fibrotic_score):
    """
    Calculate the risk score for IPF survival prediction.

    Parameters:
    GAP_score (int): The GAP score of the patient, ranging from 0 to 3.
    fibrotic_score (float): The fibrotic score of the patient, a percentage derived from thin-section CT.

    Returns:
    risk_group (str): The risk group of the patient, one of ['A1', 'A2', 'B1', 'B2'].
    """
    if GAP_score <= 3:
        if fibrotic_score < 25:
            return 'A1'
        else:
            return 'B1'
    else:
        if fibrotic_score < 25:
            return 'A2'
        else:
            return 'B2'
